    item = json.loads(line)
    q = item['base']['question']
    by_question[q].append(item)

# Check ALL questions for baseline items with missing 'answer'
count = 0
for q, items in by_question.items():
    for item in items:
        prompt_text = item['prompt'][0]['content']
        template = item.get('metadata', {}).get('prompt_template', '')
        if template == '{question}' or prompt_text.strip() == q.strip():
            if 'answer' not in item['base']:
                print(f'MISSING answer: {q[:60]}')
                print(f'  base keys: {list(item[\"base\"].keys())}')
                count += 1
                if count > 3:
                    break
    if count > 3:
        break

if count == 0:
