import json
analysis = json.loads(open('results/analysis.json').read())

# Print prevalence with CIs
print('=== Prevalence with 95% CI ===')
for key, val in analysis['prevalence'].items():
    print(f'\n{key} (N={val[\"total\"]}):')
    for mech, stats in val['stats'].items():
        if stats['count'] > 0:
            print(f'  {mech}: {stats[\"proportion\"]*100:.1f}% [{stats[\"ci_lower\"]*100:.1f}%, {stats[\"ci_upper\"]*100:.1f}%]')

# Cross-type detection
print('\n=== Cross-Type Detection ===')
ct = analysis['cross_type_detection']
print(f'Overall CV accuracy: {ct[\"overall_cv_accuracy\"]:.3f} ± {ct[\"overall_cv_std\"]:.3f}')
if 'classification_report' in ct:
    for cls, metrics in ct['classification_report'].items():
        if isinstance(metrics, dict) and 'f1-score' in metrics:
            print(f'  {cls}: F1={metrics[\"f1-score\"]:.3f}, precision={metrics[\"precision\"]:.3f}, recall={metrics[\"recall\"]:.3f}')
